import json, re

def wareki(s):
    s=s.replace(' ','').replace('　','')
    m=re.match(r'(昭和|平成|令和)(元|\d+)年(\d+)月(\d+)日',s)
    era,y,mo,d=m.groups()
    y = 1 if y=='元' else int(y)
    base={'昭和':1925,'平成':1988,'令和':2018}[era]
    return f'{base+y:04d}-{int(mo):02d}-{int(d):02d}'

