out=[]
for no,name,cat,sub,date,loc,note in rows:
    desc = f"整理番号{no}"
    if note: desc += f"、{note}"
    out.append({
        "pref":"福岡県","municipality":"みやま市","name":name,
        "category":cat,"subcategory":sub,"designation":"市指定",
        "designated_date":wareki(date),"location":loc,"description":desc,
        "source_url":url,"source_format":"pdf","fetched_at":"2026-07-12T00:00:00Z"
    })

with open("./pipeline/out/福岡県/miyama.jsonl","w",encoding="utf-8") as f:
    for r in out:
        f.write(json.dumps(r,ensure_ascii=False)+"\n")
print(len(out))
